package node

import (
	"context"
	"fmt"

	"github.com/libp2p/go-libp2p/core/host"
	"github.com/libp2p/go-libp2p/core/peer"
	"github.com/libp2p/go-libp2p/p2p/discovery/mdns"
)

const mdnsServiceTag = "groove-go.local"

// notifee satisfies mdns.Notifee. It connects to any peer discovered on the LAN.
type notifee struct {
	ctx context.Context
	h   host.Host
}

func (n *notifee) HandlePeerFound(pi peer.AddrInfo) {
	if pi.ID == n.h.ID() {
		return // skip self
	}
	fmt.Printf("[mdns] found peer: %s\n", pi.ID)
	if err := n.h.Connect(n.ctx, pi); err != nil {
		fmt.Printf("[mdns] connect failed: %s\n", err)
	}
}

// StartMDNS starts a local mDNS discovery service on the given host.
// Peers on the same LAN segment are discovered and connected automatically.
func StartMDNS(ctx context.Context, h host.Host) (mdns.Service, error) {
	svc := mdns.NewMdnsService(h, mdnsServiceTag, &notifee{ctx: ctx, h: h})
	if err := svc.Start(); err != nil {
		return nil, fmt.Errorf("mdns start: %w", err)
	}
	fmt.Printf("[mdns] service started (tag=%s)\n", mdnsServiceTag)
	return svc, nil
}

package node

import (
	"context"
	"fmt"
	"sync"

	dht "github.com/libp2p/go-libp2p-kad-dht"
	"github.com/libp2p/go-libp2p/core/host"
	"github.com/libp2p/go-libp2p/core/peer"
	"github.com/multiformats/go-multiaddr"
)

// DefaultBootstrapPeers are well-known IPFS bootstrap nodes used as DHT
// entry points when no custom bootstrap peers are provided.
var DefaultBootstrapPeers = []string{
	"/dnsaddr/bootstrap.libp2p.io/p2p/REDACTED",
	"/dnsaddr/bootstrap.libp2p.io/p2p/REDACTED",
	"/dnsaddr/bootstrap.libp2p.io/p2p/REDACTED",
	"/dnsaddr/bootstrap.libp2p.io/p2p/REDACTED",
}

// StartDHT creates a Kademlia DHT in client mode, bootstraps it, and
// returns it. The DHT enables WAN peer discovery beyond the local network.
//
// bootstrapAddrs overrides DefaultBootstrapPeers when non-empty.
func StartDHT(ctx context.Context, h host.Host, bootstrapAddrs []string) (*dht.IpfsDHT, error) {
	if len(bootstrapAddrs) == 0 {
		bootstrapAddrs = DefaultBootstrapPeers
	}

	kadDHT, err := dht.New(ctx, h, dht.Mode(dht.ModeClient))
	if err != nil {
		return nil, fmt.Errorf("dht create: %w", err)
	}

	if err := kadDHT.Bootstrap(ctx); err != nil {
		return nil, fmt.Errorf("dht bootstrap: %w", err)
	}

	// Connect to bootstrap peers in parallel; ignore individual failures.
	var wg sync.WaitGroup
	connected := 0
	var mu sync.Mutex

	for _, addrStr := range bootstrapAddrs {
		addrStr := addrStr
		wg.Add(1)
		go func() {
			defer wg.Done()
			ma, err := multiaddr.NewMultiaddr(addrStr)
			if err != nil {
				return
			}
			ai, err := peer.AddrInfoFromP2pAddr(ma)
			if err != nil {
				return
			}
			if err := h.Connect(ctx, *ai); err != nil {
				return
			}
			mu.Lock()
			connected++
			mu.Unlock()
		}()
	}
	wg.Wait()

	fmt.Printf("[dht] bootstrapped (%d/%d peers reached)\n", connected, len(bootstrapAddrs))
	return kadDHT, nil
}

