20	)
21	
22	// Message is the wire format for all workspace messages (chat and file).
23	type Message struct {
24		From      string    `json:"from"`
25		Workspace string    `json:"workspace"`
26		Body      string    `json:"body"`
27		Timestamp time.Time `json:"ts"`
28		// File fields (only set when MsgType == "file")
29		MsgType  string `json:"msg_type,omitempty"`
30		FileID   string `json:"file_id,omitempty"`
31		FileName string `json:"file_name,omitempty"`
32		FileMime string `json:"file_mime,omitempty"`
33		FileSize int64  `json:"file_size,omitempty"`
34		FileData string `json:"file_data,omitempty"` // base64-encoded bytes
35	}
36	
37	// Workspace represents a joined pubsub topic (a shared channel).
38	type Workspace struct {
39		name  string
40		self  peer.ID
41		topic *pubsub.Topic
42		sub   *pubsub.Subscription
43		ps    *pubsub.PubSub
44		store *store.Store
45	}
46	
47	// NewGossipSub creates a GossipSub router with a 16 MB max message size.
48	func NewGossipSub(ctx context.Context, h host.Host) (*pubsub.PubSub, error) {
49		ps, err := pubsub.NewGossipSub(ctx, h,
50			pubsub.WithMaxMessageSize(16*1024*1024),
51		)
52		if err != nil {
53			return nil, fmt.Errorf("gossipsub: %w", err)
54		}
55		fmt.Println("[transport] GossipSub router started")
56		return ps, nil
57	}
58	
59	// JoinWorkspace joins (or creates) a pubsub topic for the named workspace.
60	func JoinWorkspace(ps *pubsub.PubSub, self peer.ID, name string, s *store.Store) (*Workspace, error) {
61		topic, err := ps.Join("workspace-" + name)
62		if err != nil {
63			return nil, fmt.Errorf("join topic: %w", err)
64		}
65		sub, err := topic.Subscribe()
66		if err != nil {
67			return nil, fmt.Errorf("subscribe: %w", err)
68		}
69		fmt.Printf("[transport] joined workspace: %s\n", name)
70		return &Workspace{name: name, self: self, topic: topic, sub: sub, ps: ps, store: s}, nil
71	}
72	
73	// Publish sends a chat message to the workspace topic and persists it locally.
74	func (w *Workspace) Publish(ctx context.Context, body string) error {
75		msg := Message{
76			MsgType:   MsgTypeChat,
77			From:      w.self.String(),
78			Workspace: w.name,
79			Body:      body,
80			Timestamp: time.Now().UTC(),
81		}
82		return w.publish(ctx, msg)
83	}
84	
85	// PublishFile sends a file to the workspace topic (max 10 MB).
86	func (w *Workspace) PublishFile(ctx context.Context, fileID, fileName, mime string, data []byte) error {
87		if len(data) > MaxFileSize {
88			return fmt.Errorf("file too large (%d bytes, max %d)", len(data), MaxFileSize)
